// =========================================================
// MOTORE RAY MARCHING 4D: SUPERFICIE DI LAWSON (Genere 2)
// =========================================================

// Rotazione 4D (Sfrutta le variabili globali del tuo programma)
vec4 rotate4D(vec4 p) {
    // Se u_omega, u_phi, u_psi non sono disponibili, usa iTime
    float omega = iTime * 0.3; // Sostituisci con u_omega se mappato nel tuo shader
    float phi   = iTime * 0.2; // Sostituisci con u_phi
    float psi   = iTime * 0.1; // Sostituisci con u_psi

    float co = cos(omega), so = sin(omega);
    float cp = cos(phi),   sp = sin(phi);
    float cs = cos(psi),   ss = sin(psi);

    // Rotazione nei piani 4D
    float x1 = p.x * co - p.w * so;
    float w1 = p.x * so + p.w * co;
    vec4 p1 = vec4(x1, p.y, p.z, w1);

    float y2 = p1.y * cp - p1.w * sp;
    float w2 = p1.y * sp + p1.w * cp;
    vec4 p2 = vec4(p1.x, y2, p1.z, w2);

    float z3 = p2.z * cs - p2.w * ss;
    float w3 = p2.z * ss + p2.w * cs;

    return vec4(p2.x, p2.y, z3, w3);
}

// Funzione Distanza (SDF) per la Lawson Implicita
float map(vec3 p3D) {
    // 1. Proiezione Stereografica Inversa: 
    // Prendiamo lo spazio 3D infinito e lo "arrotoliamo" sull'Ipersfera 4D (S^3)
    float r2 = dot(p3D, p3D);
    vec4 p4 = vec4(2.0 * p3D, r2 - 1.0) / (r2 + 1.0);

    // 2. Ruotiamo l'Ipersfera in 4D
    p4 = rotate4D(p4);

    // 3. Equazione Implicita di Lawson: 3x^2y - y^3 + 2zw = 0
    float x = p4.x;
    float y = p4.y;
    float z = p4.z;
    float w = p4.w;

    float lawsonValue = 3.0 * x * x * y - y * y * y + 2.0 * z * w;

    // 4. Creiamo uno "spessore" per renderla solida (es. 0.05)
    // Moltiplichiamo per 0.5 per stabilizzare il Ray Marching sulla geometria curva
    return (abs(lawsonValue) - 0.04) * 0.5;
}

// Calcolo matematico della Normale per luci e riflessi
vec3 calcNormal(vec3 p) {
    vec2 e = vec2(0.005, 0.0);
    return normalize(vec3(
        map(p + e.xyy) - map(p - e.xyy),
        map(p + e.yxy) - map(p - e.yxy),
        map(p + e.yyx) - map(p - e.yyx)
    ));
}

void mainImage( out vec4 fragColor, in vec2 fragCoord ) {
    // Normalizza lo schermo (-1 a 1)
    vec2 uv = (fragCoord - 0.5 * iResolution.xy) / iResolution.y;

    // Setup della "Videocamera" per il Raymarching
    vec3 rayOrigin = vec3(0.0, 0.0, 4.0);     // Arretriamo la camera di 4 unità
    vec3 rayDir = normalize(vec3(uv, -1.0));  // Spara raggi verso lo schermo

    float t = 0.0;           // Distanza percorsa dal raggio
    float maxDist = 20.0;    // Limite di visuale
    int maxSteps = 150;      // Precisione della ricerca
    float dist = 0.0;
    vec3 p;

    // Motore di Sphere Tracing
    for(int i = 0; i < maxSteps; i++) {
        p = rayOrigin + rayDir * t;
        dist = map(p);
        if(dist < 0.001 || t > maxDist) break; // Colpito o perso nel vuoto
        t += dist;
    }

    // Colore di Sfondo base (Grigio cosmico sfumato)
    vec3 color = vec3(0.1, 0.1, 0.12) * (1.0 - length(uv) * 0.4);

    // Se il raggio ha colpito la superficie matematica:
    if(t < maxDist) {
        vec3 normal = calcNormal(p);

        // Illuminazione Direzionale Morbida
        vec3 lightDir = normalize(vec3(1.0, 2.0, 1.5));
        float diff = max(dot(normal, lightDir), 0.0);
        float ambient = 0.15;

        // Materiale: Turchese Matematico Elegante
        vec3 objColor = vec3(0.1, 0.8, 0.6);
        color = objColor * (diff + ambient);

        // Riflesso Speculare tipo Plastica/Vetro
        vec3 viewDir = normalize(rayOrigin - p);
        vec3 reflectDir = reflect(-lightDir, normal);
        float spec = pow(max(dot(viewDir, reflectDir), 0.0), 64.0);
        color += vec3(1.0) * spec * 0.6;

        // Ombreggiatura sui bordi (Fresnel) per far risaltare i buchi
        float fresnel = pow(1.0 - max(dot(normal, viewDir), 0.0), 3.0);
        color += vec3(0.5, 0.9, 0.8) * fresnel * 0.5;
    }

    fragColor = vec4(color, 1.0);
}

