// --- PARAMETRI ---
vec3 c1 = u_col1; // Colore 1 dall'interfaccia
vec3 c2 = u_col2; // Colore 2 dall'interfaccia

// Parametri Marmo
float density = 10.0;
float turbulence = 4.0;

// Coordinate scalate (u, v sono disponibili grazie a common.glsl)
vec2 p = vec2(u, v) * 4.0;

// --- CALCOLO TURBOLENZA ---
float tVal = 0.0;
float amp = 1.0;
float freq = 1.0;

for(int i = 0; i < 3; i++) {
    // [FIX] Usa 'sys_noise' invece di 'noise'
    tVal += sys_noise(p * freq) * amp;
    amp *= 0.5;
    freq *= 2.0;
}

// --- FORMULA MARMO ---
// Distorce le linee diagonali (x + y) con il rumore
float xyValue = p.x + p.y + (tVal * turbulence);

// Crea le venature usando il seno
float val = sin(xyValue * density);

// Mappa da [-1, 1] a [0, 1] per il mix
float mixFactor = (val + 1.0) * 0.5;

// Interpolazione finale tra i due colori scelti
return mix(c1, c2, mixFactor);
